import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/99-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/99-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/99-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 么他是否放弃计划,或在实施计划时成败与否,对诸位大人来说都是一样 的。现在,让我判断皇帝此战能否得胜,对我来说就更困难了。因为我既 不知道威尼斯人实力如何,也不知道法国的备战情况。诸位大人也从未在 任何信中,告诉我这方面的情况。如果要远距离做出判断的话,我只能猜 测威尼斯人的实力十分强大。因为我看到皇帝的2支部队,每支都有6000 到7000人。其中一支部队被打败了,而另一支则停步不前。如此看来,如 果皇帝要同时打败威尼斯人和法国,那总共要有多少兵力?此外,如果我 能得知米兰人正在做什么事,他们备战情况如何,法国将会站在哪一边, 威尼斯人拥有怎样的部队,他们是否能够应付部队的开支;最后,我还要 知道,法国和威尼斯人是否会联合起来保卫意大利,那么,我才能斗胆得 出结论,不用太担心会犯错。但情况如此,我只能请求上帝护佑。我还希 望无论我采取什么行动,诸位大人都能相信我那么做是出于最好的意愿, 并期望那样的做法是最明智的选择。 正如我在之前的信中所说的,也可能在没有出现任何明显迹象的时 候 , 突然达成了和平协议。对此,任何人都无法预知。确实,我在过去2 天中听说,现在皇帝的愤怒都转向威尼斯人,于是他表现出要与法国和 好的样子。他这样的意向,也得到特使和阿拉贡大使的支持。甚至还有传 闻,特使已经应皇帝的要求,就这个问题写信给法国。这么做的困难只有 一个,那就是:法国不知道能够以什么理由抛弃威尼斯人,如何在某种保 护色的掩饰下做得心安理得。对此,特使建议法国国王在里昂召集会议。 并在会议上向威尼斯人宣布:如果他们能够给国王提供一笔600000达克特 的特殊津贴,那么国王不仅会保护米兰人,还会为了他的荣誉和利益向德 意志开战。但是,如果他们不能提供这笔钱,那他就只好被迫抛弃威尼斯 人,为自己创造和平。大家认为,比起自己付出代价参与战争(即使有希 望得到一些收获),两国元首更喜欢以别人的代价换取和平。因此,法国 可能会以某种方式抛弃威尼斯人,而不顾他们的抗议吵闹。诸位大人可以 在里昂打探消息,看看这是真实的,还是纯属虚构。这件事,我只是按照",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
